#nullable enable // autogenerated

using MVZ2Logic;
using MVZ2Logic.Definitions;
using MVZ2Logic.Options;

namespace MVZ2.GameContent.Options
{
    [AutoOptionWidgetDefinition(LogicOptionWidgetNames.fullscreen)]
    public class FullscreenOptionToggle : OptionToggleDefinition
    {
        public FullscreenOptionToggle(string nsp, string name) : base(nsp, name)
        {
        }
        public override bool ShouldEnable(IOptionContext context)
        {
            return !Global.Game.IsMobile();
        }
        public override bool GetValue(IOptionContext context)
        {
            return Global.Options.GetOptionBool(LogicOptionItemID.fullscreen);
        }

        public override void OnValueChanged(IOptionContext context, bool value)
        {
            Global.Options.SetOptionBool(LogicOptionItemID.fullscreen, value);
            Global.Options.SaveOptions();
        }
    }
}
